<?php
namespace WCPOS\WooCommercePOS\SquareTerminal\Tests\Includes;
use PHPUnit\Framework\TestCase; use WCPOS\WooCommercePOS\SquareTerminal\Services\SquareTerminalAdapter;
use WCPOS\WooCommercePOS\SquareTerminal\Vendor\Square\Terminal\Checkouts\Requests\CreateTerminalCheckoutRequest;
use WCPOS\WooCommercePOS\SquareTerminal\Vendor\Square\Types\{CreateTerminalCheckoutResponse, TerminalCheckout, Money, DeviceCheckoutOptions};
final class SpyCheckoutsClient { public ?CreateTerminalCheckoutRequest $createdRequest=null; public function create(CreateTerminalCheckoutRequest $request){ $this->createdRequest=$request; return new CreateTerminalCheckoutResponse(['checkout'=>new TerminalCheckout(['id'=>'chk_123','amountMoney'=>new Money(['amount'=>1234,'currency'=>'USD']),'deviceOptions'=>new DeviceCheckoutOptions(['deviceId'=>'DEVICE123']),'referenceId'=>'woocommerce_order_99','status'=>'PENDING','paymentIds'=>['pay_1']])]); }}
final class SquareTerminalAdapterTest extends TestCase { public function test_create_checkout_uses_real_typed_request_and_normalizes_response(): void { $spy=new SpyCheckoutsClient(); $client=(object)['terminal'=>(object)['checkouts'=>$spy]]; $result=(new SquareTerminalAdapter($client))->create_checkout(['amount'=>1234,'currency'=>'USD','device_id'=>'DEVICE123','reference_id'=>'woocommerce_order_99','idempotency_key'=>'idem']); self::assertInstanceOf(CreateTerminalCheckoutRequest::class,$spy->createdRequest); $checkout=$spy->createdRequest->getCheckout(); self::assertSame(1234,$checkout->getAmountMoney()->getAmount()); self::assertSame('USD',$checkout->getAmountMoney()->getCurrency()); self::assertSame('DEVICE123',$checkout->getDeviceOptions()->getDeviceId()); self::assertSame('woocommerce_order_99',$checkout->getReferenceId()); self::assertSame(['id'=>'chk_123','status'=>'PENDING','reference_id'=>'woocommerce_order_99','payment_ids'=>['pay_1']],$result); }}
